3.8 数据质量检查基础
在采样现场和实验室阶段，应该进行初步的数据质量检查。以下是一套基础的数据质量检查函数：
# ============================================
# 数据质量检查函数包
# ============================================

check_missing &lt;- function(df, threshold = 0.1) {
  missing_ratio &lt;- colSums(is.na(df)) / nrow(df)
  high_missing &lt;- missing_ratio[missing_ratio &gt; threshold]

  if (length(high_missing) &gt; 0) {
    message("以下变量缺失比例超过 ", threshold * 100, "%：")
    print(high_missing)
  } else {
    message("无高缺失比例变量")
  }
  invisible(missing_ratio)
}

check_outliers &lt;- function(x, method = "sd", n_sd = 3) {
  if (method == "sd") {
    outliers &lt;- abs(x - mean(x, na.rm = TRUE)) &gt; n_sd * sd(x, na.rm = TRUE)
  } else if (method == "iqr") {
    q1 &lt;- quantile(x, 0.25, na.rm = TRUE)
    q3 &lt;- quantile(x, 0.75, na.rm = TRUE)
    iqr &lt;- q3 - q1
    outliers &lt;- x &lt; (q1 - 1.5 * iqr) | x &gt; (q3 + 1.5 * iqr)
  }
  return(outliers)
}

check_range &lt;- function(x, valid_min, valid_max, var_name = "变量") {
  out_of_range &lt;- x &lt; valid_min | x &gt; valid_max
  n_out &lt;- sum(out_of_range, na.rm = TRUE)

  if (n_out &gt; 0) {
    message(var_name, " 有 ", n_out, " 个值超出范围 [",
            valid_min, ", ", valid_max, "]")
    return(which(out_of_range))
  } else {
    message(var_name, " 所有值在合理范围内")
    return(integer(0))
  }
}

check_duplicates &lt;- function(df, key_vars) {
  library(dplyr)
  dup_rows &lt;- df %&gt;%
    select(all_of(key_vars)) %&gt;%
    group_by(across(all_of(key_vars))) %&gt;%
    filter(n() &gt; 1) %&gt;%
    ungroup()

  if (nrow(dup_rows) &gt; 0) {
    message("发现 ", nrow(dup_rows), " 条重复记录：")
    print(dup_rows)
    return(TRUE)
  } else {
    message("无重复记录")
    return(FALSE)
  }
}

generate_quality_report &lt;- function(df) {
  cat("\n========== 数据质量报告 ==========\n")
  cat("数据维度：", nrow(df), "行 ×", ncol(df), "列\n\n")
  cat("【缺失值检查】\n")
  check_missing(df)
  cat("\n【数据类型检查】\n")
  print(table(sapply(df, class)))
  cat("\n【数值变量描述统计】\n")
  num_cols &lt;- names(df)[sapply(df, is.numeric)]
  if (length(num_cols) &gt; 0) print(summary(df[, num_cols]))
  cat("\n========== 报告生成完毕 ==========\n")
}
使用示例：
# 对土壤采样数据进行质量检查
generate_quality_report(soil_samples)

# 检查孔隙度范围（合理范围 30%-70%）
check_range(soil_samples$porosity, 30, 70, "土壤孔隙度")

# 检查重复记录（基于样地+土层）
check_duplicates(soil_samples, c("plot_id", "soil_depth"))






Note数据质量检查的黄金法则



宁可在采样现场发现并纠正问题，不要等到数据分析阶段才发现数据不可用。
在现场，应做到： 1. 每批次采样后立即记录和检查 2. 设置合理的数据范围阈值 3. 对可疑值重新测量确认 4. 完整记录所有异常情况

8.9 forcats：因子变量处理
因子（factor）是 R 中用于表示分类变量的数据类型，在生态学中常用于物种分类、生境类型、调查月份等。

8.9.1 创建与转换因子
# 使用 factor() 创建因子
habitat_factor &lt;- factor(c("山脊", "山谷", "山坡", "山谷", "山脊"))
habitat_factor

# 指定因子水平顺序（影响排列和绘图顺序）
habitat_ordered &lt;- factor(
  c("山谷", "山坡", "山脊"),
  levels = c("山谷", "山坡", "山脊")  # 从低到高排列
)
habitat_ordered


8.9.2 常用 forcats 函数
改变水平顺序：
# fct_relevel()：手动调整水平顺序（将参照水平放第一位）
survey |&gt;
  mutate(habitat = fct_relevel(habitat, "山谷")) |&gt;
  pull(habitat) |&gt;
  levels()

# fct_reorder()：按另一变量统计量排序
survey |&gt;
  group_by(habitat) |&gt;
  summarise(mean_h = mean(height, na.rm = TRUE)) |&gt;
  mutate(habitat = fct_reorder(habitat, mean_h)) |&gt;
  pull(habitat) |&gt;
  levels()
合并与重编码水平：
# fct_collapse()：将多个水平合并为一个
survey |&gt;
  mutate(
    habitat_big = fct_collapse(
      habitat,
      "低海拔" = c("山谷"),
      "中海拔" = c("山坡"),
      "高海拔" = c("山脊")
    )
  ) |&gt;
  count(habitat_big)
处理稀有水平：
# fct_lump_min()：将出现次数少于阈值的水平合并为"其他"
survey |&gt;
  mutate(species_lumped = fct_lump_min(species, min = 5)) |&gt;
  count(species_lumped)

# fct_lump_n()：保留出现最多的 n 个，其余归为"其他"
survey |&gt;
  mutate(species_top3 = fct_lump_n(species, n = 3)) |&gt;
  count(species_top3)


8.9.3 生态学应用：生境与物种分析
# 按生境统计并确保生境水平按样地海拔排序
habitat_summary &lt;- survey |&gt;
  filter(!is.na(height)) |&gt;
  mutate(
    # 调整生境水平顺序（山谷→山坡→山脊，体现海拔梯度）
    habitat = fct_relevel(habitat, "山谷", "山坡", "山脊")
  ) |&gt;
  group_by(habitat) |&gt;
  summarise(
    n = n(),
    mean_height = round(mean(height), 2),
    mean_dbh = round(mean(dbh, na.rm = TRUE), 2)
  )

habitat_summary
